"use client"
import {
  NavigationItem,
} from "@/components/atoms"
import { useUnreads } from "@talkjs/react"
import { usePathname } from "next/navigation"

const navigationItems = [
  { label: "Orders", href: "/user/orders" },
  { label: "Messages", href: "/user/messages" },
  { label: "Returns", href: "/user/returns" },
  { label: "Addresses", href: "/user/addresses" },
  { label: "Reviews", href: "/user/reviews" },
  { label: "Wishlist", href: "/user/wishlist" },
]

export const UserNavigation = () => {
  const unreads = useUnreads()
  const path = usePathname()

  return (
    <nav
      className="h-min rounded-[14px] overflow-hidden"
      style={{ background: "var(--bg-surface-1, #18162A)", border: "1px solid var(--border-default, #2C2A4A)" }}
    >
      <div className="py-2">
        {navigationItems.map((item) => (
          <NavigationItem
            key={item.label}
            href={item.href}
            active={path === item.href}
            className="relative"
          >
            {item.label}
            {item.label === "Messages" && Boolean(unreads?.length) && (
              <span
                className="absolute top-3 left-24 w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-bold text-white"
                style={{ background: "var(--brand-primary, #8B5CF6)" }}
              >
                {unreads?.length}
              </span>
            )}
          </NavigationItem>
        ))}
      </div>
      <div style={{ borderTop: "1px solid var(--border-default, #2C2A4A)" }} className="py-2">
        <NavigationItem
          href="/user/settings"
          active={path === "/user/settings"}
        >
          Settings
        </NavigationItem>
      </div>
    </nav>
  )
}

import Link from "next/link"

interface InfoPageSection {
  title: string
  content: string[]
}

interface InfoPageLink {
  href: string
  label: string
}

interface InfoPageProps {
  eyebrow: string
  title: string
  description: string
  sections: InfoPageSection[]
  links?: InfoPageLink[]
}

export function InfoPage({
  eyebrow,
  title,
  description,
  sections,
  links = [],
}: InfoPageProps) {
  return (
    <main className="px-5 py-10 md:px-12 md:py-16">
      <div className="mx-auto max-w-4xl">
        <header className="mb-10 rounded-[24px] border border-default bg-surface-1 p-8 md:p-10">
          <p className="mb-3 font-barlow text-xs font-semibold uppercase tracking-[0.18em] text-brand-primary">
            {eyebrow}
          </p>
          <h1 className="mb-4 font-barlow-condensed text-[36px] font-bold leading-none text-primary md:text-[48px]">
            {title}
          </h1>
          <p className="max-w-3xl text-base leading-7 text-secondary">
            {description}
          </p>
          {links.length > 0 && (
            <div className="mt-6 flex flex-wrap gap-3">
              {links.map((link) => (
                <Link
                  key={`${link.href}-${link.label}`}
                  href={link.href}
                  className="rounded-full border border-default px-4 py-2 text-sm font-medium text-secondary transition-colors hover:border-brand-primary hover:text-primary"
                >
                  {link.label}
                </Link>
              ))}
            </div>
          )}
        </header>

        <div className="space-y-6">
          {sections.map((section) => (
            <section
              key={section.title}
              className="rounded-[20px] border border-default bg-surface-1 p-6 md:p-8"
            >
              <h2 className="mb-4 font-barlow text-lg font-semibold text-primary">
                {section.title}
              </h2>
              <div className="space-y-3 text-sm leading-7 text-secondary md:text-base">
                {section.content.map((paragraph) => (
                  <p key={paragraph}>{paragraph}</p>
                ))}
              </div>
            </section>
          ))}
        </div>
      </div>
    </main>
  )
}

